458	
459		return &status, nil
460	}
461	
462	// Signout will signout a client for a local ollama server.
463	func (c *Client) Signout(ctx context.Context) error {
464		return c.do(ctx, http.MethodPost, "/api/signout", nil, nil)
465	}
466	
467	// Disconnect will disconnect an ollama instance from ollama.com.
468	func (c *Client) Disconnect(ctx context.Context, encodedKey string) error {
469		return c.do(ctx, http.MethodDelete, fmt.Sprintf("/api/user/keys/%s", encodedKey), nil, nil)
