282	func remoteURL(raw string) (string, error) {
283		// Special‑case: user supplied only a path ("/foo/bar").
284		if strings.HasPrefix(raw, "/") {
285			return (&url.URL{
286				Scheme: "http",
287				Host:   net.JoinHostPort("localhost", "11434"),
288				Path:   path.Clean(raw),
289			}).String(), nil
290		}
291	
292		if !strings.Contains(raw, "://") {
293			raw = "http://" + raw
294		}
295	
296		if raw == "ollama.com" || raw == "http://ollama.com" {
297			raw = "https://ollama.com:443"
298		}
299	
300		u, err := url.Parse(raw)
301		if err != nil {
302			return "", fmt.Errorf("parse error: %w", err)
303		}
304	
305		if u.Host == "" {
306			u.Host = "localhost"
307		}
308	
309		hostPart, portPart, err := net.SplitHostPort(u.Host)
310		if err == nil {
311			u.Host = net.JoinHostPort(hostPart, portPart)
312		} else {
313			u.Host = net.JoinHostPort(u.Host, "11434")
314		}
315	
316		if u.Path != "" {
317			u.Path = path.Clean(u.Path)
318		}
319	
320		if u.Path == "/" {
321			u.Path = ""
322		}
323	
324		return u.String(), nil
325	}
